//////////////////// START OF src/Utilities/DebugChecks.hpp ////////////////////

#ifdef POKESIM_DEBUG_CHECK_UTILITIES

namespace pokesim::debug {
struct Checks {
  Checks(const Simulation& _simulation)
      : simulation(&_simulation),
        registry(&_simulation.registry),
        simulateTurnOptionsOnInput(simulation->simulateTurnOptions),
        calcDamageOptionsOnInput(simulation->calculateDamageOptions),
        analyzeEffectOptionsOnInput(simulation->analyzeEffectOptions) {}

 protected:
  const Simulation* simulation;
  const types::registry* registry;
  types::registry registryOnInput;
  simulate_turn::Options simulateTurnOptionsOnInput;
  calc_damage::Options calcDamageOptionsOnInput;
  analyze_effect::Options analyzeEffectOptionsOnInput;

  entt::dense_map<types::entity, types::entity> currentEntitiesToInitial;
  entt::dense_set<types::entity> specificallyChecked;
  types::entityIndex initialEntityCount = 0U;

  template <typename T>
  bool has(types::entity entity) const {
    return registry->all_of<T>(entity);
  }

  types::entity getInitialEntity(types::entity entity) const {
    types::entity parent = findCopyParent(currentEntitiesToInitial, *registry, entity);
    return currentEntitiesToInitial.at(parent);
  }

  void copyEntity(types::entity entity) {
    currentEntitiesToInitial[entity] = createEntityCopy(entity, *registry, registryOnInput);
  }

  void copyRemainingEntities() {
    for (types::entity entity : registry->view<types::entity>()) {
      if (!registry->orphan(entity)) {
        initialEntityCount++;
        if (currentEntitiesToInitial.contains(entity)) {
          specificallyChecked.emplace(entity);
        }
        else {
          copyEntity(entity);
        }
      }
    }
  }

  void checkOptions() const {
    POKESIM_REQUIRE_NM(simulateTurnOptionsOnInput == simulation->simulateTurnOptions);
    POKESIM_REQUIRE_NM(calcDamageOptionsOnInput == simulation->calculateDamageOptions);
    POKESIM_REQUIRE_NM(analyzeEffectOptionsOnInput == simulation->analyzeEffectOptions);
  }

  void checkRemainingOutputs() const {
    for (auto [original, copy] : currentEntitiesToInitial) {
      if (!specificallyChecked.contains(original)) {
        areEntitiesEqual(*registry, original, registryOnInput, copy);
      }
    }
  }

  types::entityIndex getFinalEntityCount() const {
    types::entityIndex finalEntityCount = 0U;
    for (types::entity entity : registry->view<types::entity>()) {
      if (!registry->orphan(entity)) {
        finalEntityCount++;
      }
    }
    return finalEntityCount;
  }

  void checkPokemon(types::entity pokemonEntity) const { pokesim::debug::checkPokemon(pokemonEntity, *registry); }
  void checkSide(types::entity sideEntity) const { pokesim::debug::checkSide(sideEntity, *registry); }
  void checkBattle(types::entity battleEntity) const { pokesim::debug::checkBattle(battleEntity, *registry); }
};
}  // namespace pokesim::debug

#else
namespace pokesim::debug {
struct Checks {};
}  // namespace pokesim::debug
#endif

